pages.css:
.page-01 {
  background-color: #FFFFFF;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  padding: 100px 96px;
  display: flex;
  flex-direction: column;
}

.header {
  display: flex;
  align-items: center;
  gap: 16px;
  font-size: 40px;
  font-weight: 600;
  color: #D92D20;
}

.title-box {
  margin-top: 220px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.title-line {
  font-size: 124px;
  font-weight: 900;
  line-height: 1.2;
  color: #101828;
  margin: 0;
  letter-spacing: 0;
  word-wrap: break-word;
}

.title-line:nth-child(2) {
  color: #D92D20;
}

.content-box {
  margin-top: auto;
  border-top: 4px solid #101828;
  padding-top: 72px;
  display: flex;
  flex-direction: column;
  gap: 64px;
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.sub-tag {
  font-size: 34px;
  font-weight: 700;
  color: #344054;
  background-color: #F2F4F7;
  padding: 10px 24px;
  border-radius: 8px;
  width: fit-content;
  letter-spacing: 0;
}

.sub-text {
  font-size: 44px;
  line-height: 1.6;
  color: #475467;
  font-weight: 400;
  margin: 0;
  letter-spacing: 0;
}

.page-02 {
  width: 1242px;
  height: 1660px;
  background-color: #F4F5F7;
  box-sizing: border-box;
  padding: 88px 100px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  color: #111111;
  position: relative;
  overflow: hidden;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 48px;
}

.header-icon {
  font-size: 48px;
}

.header-label {
  font-size: 38px;
  font-weight: 600;
  color: #888888;
  letter-spacing: 0;
}

.page-title {
  margin-bottom: 64px;
}

.page-title p {
  font-size: 100px;
  font-weight: 800;
  line-height: 1.25;
  margin: 0;
  letter-spacing: 0;
  color: #111111;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 32px;
  flex: 1;
}

.proof-item {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 40px 48px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.02);
  border-left: 8px solid #D93025;
}

.proof-tag {
  font-size: 34px;
  font-weight: 700;
  color: #D93025;
  letter-spacing: 0;
  text-transform: uppercase;
  display: flex;
  align-items: center;
}

.proof-tag::before {
  content: "";
  display: inline-block;
  width: 12px;
  height: 12px;
  background-color: #D93025;
  border-radius: 50%;
  margin-right: 16px;
}

.proof-text {
  font-size: 42px;
  line-height: 1.45;
  color: #222222;
  font-weight: 500;
  margin: 0;
  letter-spacing: 0;
}

.page-03 {
  width: 1242px;
