}

.page-title-section {
  display: flex;
  flex-direction: column;
  gap: 16px;
  margin-bottom: 60px;
}

.page-title {
  font-size: 100px;
  font-weight: 800;
  line-height: 1.2;
  color: #FFFFFF;
  letter-spacing: 0;
}

.page-highlight {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  margin-bottom: 60px;
  padding-left: 32px;
  border-left: 12px solid #E65A28;
}

.highlight-number {
  font-size: 140px;
