}

.proof-item {
  display: flex;
  align-items: flex-start;
  gap: 32px;
  background: #1C1C1E;
  padding: 32px;
  border-radius: 16px;
}

.proof-tag {
  flex-shrink: 0;
  background: #333336;
  color: #FFFFFF;
  font-size: 36px;
  font-weight: 700;
  padding: 12px 20px;
  border-radius: 8px;
  letter-spacing: 0;
