}

.proof-text {
  font-size: 38px;
  line-height: 1.5;
  color: #D1D1D6;
  letter-spacing: 0;
}

.page-footnote {
  margin-top: auto;
  font-size: 32px;
  color: #8E8E93;
  line-height: 1.5;
  border-top: 2px solid #2C2C2E;
  padding-top: 24px;
  letter-spacing: 0;
}

